      cwd: tmpDir,
      timeout: 300_000,
      env: { ...process.env },
      maxBuffer: 10 * 1024 * 1024,
    });

    actOutput = actResult.stdout?.toString() ?? "";
    actOutput += actResult.stderr?.toString() ?? "";
